#include<bits/stdc++.h>
using namespace std;
bool v[60][60][1005];
char c[60][60];
int cc,r,n;
map<string,int> m;
string a[1005];
void dfs(int x,int y,int step){
    /*if(v[x][y][step]){
        return;
    }*/
    if(step>=n){
        c[x][y]='*';
        return;
    }
    //v[x][y][step]=1;
    if(m[string(a[step])]==1){
        for(int i=x-1;i>=1;i--){
            if(c[i][y]=='X'){
                break;
            }else{
                dfs(i,y,step+1);
            }
        }
    }else if(m[a[step]]==2){
        for(int i=x+1;i<=r;i++){
            if(c[i][y]=='X'){
                break;
            }else{
                dfs(i,y,step+1);
            }
        }
    }else if(m[a[step]]==3){
        for(int i=y-1;i>=1;i--){
            if(c[x][i]=='X'){
                break;
            }else{
                dfs(x,i,step+1);
            }
        }
    }else{
        for(int i=y+1;i<=cc;i++){
            if(c[x][i]=='X'){
                break;
            }else{
                dfs(x,i,step+1);
            }
        }
    }
}
int main(){
    m["NORTH"]=1;
    m["SOUTH"]=2;
    m["WEST"]=3;
    m["EAST"]=4;
    cin>>r>>cc;
    int xx,yy;
    for(int i=1;i<=r;i++){
        for(int j=1;j<=cc;j++){
            cin>>c[i][j];
            if(c[i][j]=='*'){
                xx=i;
                yy=j;
                c[i][j]='.';
            }
        }
    }
    cin>>n;
    for(int i=0;i<n;i++) cin>>a[i];
    dfs(xx,yy,0);
    for(int i=1;i<=r;i++){
        for(int j=1;j<=cc;j++){
            cout<<c[i][j];
        }
        cout<<"\n";
    }
    return 0;
}
